select v_1 as "l_returnflag", v_2 as "l_linestatus", v_3 as "sum_qty", v_4 as "sum_base_price", v_5 as "sum_disc_price", v_6 as "sum_charge", v_7 as "avg_qty", v_8 as "avg_price", v_9 as "avg_disc", v_10 as "count_order" from (select v_11 as v_1, v_12 as v_2, sum(v_13) as v_3, sum(v_14) as v_4, sum(v_14 * (cast('1' as integer) - v_15)) as v_5, sum((v_14 * (cast('1' as integer) - v_15)) * (cast('1' as integer) + v_16)) as v_6, avg(v_13) as v_7, avg(v_14) as v_8, avg(v_15) as v_9, count(*) as v_10 from (select * from (select "l_quantity" as v_13, "l_extendedprice" as v_14, "l_discount" as v_15, "l_tax" as v_16, "l_returnflag" as v_11, "l_linestatus" as v_12, "l_shipdate" as v_17 from "lineitem") s where v_17 <= (date('1998-12-01', '-90 days'))) s group by 1, 2) s order by v_1, v_2
